import React, { useEffect, useState } from 'react';
import CommandeForm from './CommandeForm.js';
import './CommandeList.css'; 

const CommandeList = () => {
  const [commandes, setCommandes] = useState([]);

  const fetchCommandes = () => {
    fetch('http://localhost:3001/commandes')
      .then(res => res.json())
      .then(data => setCommandes(data))
      .catch(err => console.error('Erreur chargement commandes:', err));
  };

  useEffect(() => {
    fetchCommandes();
  }, []);

  return (
    <div>
      <h2>Ajouter une Commande</h2>
      <CommandeForm onCommandeAdded={fetchCommandes} />

      <h2>Liste des Commandes</h2>
      <table className="commande-table">
        <thead>
          <tr>
            <th>Code</th>
            <th>Client</th>
            <th>Article</th>
            <th>Date</th>
            <th>Quantité</th>
          </tr>
        </thead>
        <tbody>
          {commandes.map(com => (
            <tr key={com.codeCom}>
              <td>{com.codeCom}</td>
              <td>{com.nomCli} {com.prenomCli}</td>
              <td>{com.nomArt}</td>
              <td>{com.dateCom}</td>
              <td>{com.QteCom}</td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
};

export default CommandeList;
